-- Contractor brief schema v4: English UI, no testimonials, compact business hours

do $$
declare
  contractor_schema jsonb := '{"sections":[{"id":"confirm_data","title":"Confirm your details","description":"Review what we already have on file and fill in anything that''s missing.","fields":[{"key":"contact_name","type":"text","label":"Contact name","required":true},{"key":"contact_email","type":"email","label":"Contact email","required":true},{"key":"contact_phone","type":"phone","label":"Contact phone","required":true},{"key":"company_name","type":"text","label":"Company name","required":true},{"key":"use_same_contact_for_business","type":"checkbox","label":"Use the same email and phone for the business"},{"key":"business_email","type":"email","label":"Business email","visible_when":{"operator":"and","conditions":[{"field":"use_same_contact_for_business","op":"is_empty"}]}},{"key":"business_phone","type":"phone","label":"Business phone","visible_when":{"operator":"and","conditions":[{"field":"use_same_contact_for_business","op":"is_empty"}]}},{"key":"full_address","type":"textarea","label":"Full business address","required":true},{"key":"existing_website","type":"text","label":"Current website (if any)","placeholder":"www.yourcompany.com"},{"key":"social_links","type":"dynamic_list","label":"Social media","min_items":0,"add_button_label":"Add social profile","item_label_template":"Social profile {index}","item_placeholder":"e.g. Facebook|facebook.com/yourcompany","help_text":"Optional. Add each profile you use (Facebook, Instagram, etc.)."}]},{"id":"about_business","title":"About your business","fields":[{"key":"company_founded_year","type":"number","label":"Year the company was founded","min":1900,"max":2026},{"key":"years_experience","type":"number","label":"Years of experience (calculated)","help_text":"Calculated automatically from the founding year."},{"key":"has_insurance","type":"radio","label":"Do you carry insurance?","options":["Yes","No"]},{"key":"license_number","type":"text","label":"License number","visible_when":{"operator":"and","conditions":[{"field":"has_insurance","op":"equals","value":"Yes"}]}},{"key":"service_areas","type":"textarea","label":"Service areas / cities you work in"},{"key":"business_hours","type":"textarea","label":"Business hours"}]},{"id":"web_content","title":"Story & website content","description":"This helps us write your About, homepage, and trust sections.","fields":[{"key":"company_story","type":"textarea","label":"Company story","help_text":"How the business started, who founded it, milestones, and what makes you unique today.","placeholder":"e.g. We started in 2010 as a two-person family team and now serve the whole county…"},{"key":"company_tagline","type":"text","label":"Tagline or main headline","placeholder":"e.g. \"Quality in every project\" or \"Your home, our priority\""},{"key":"why_choose_us","type":"textarea","label":"Why should customers choose you?","help_text":"3–5 clear reasons for a new visitor (experience, warranty, speed, etc.)."},{"key":"certifications_awards","type":"textarea","label":"Certifications, awards, or memberships","placeholder":"e.g. License #12345, BBB A+, NARI member, Best of 2024…"},{"key":"warranties_guarantees","type":"textarea","label":"Warranties you offer","placeholder":"e.g. 10-year materials warranty, 2-year workmanship…"},{"key":"emergency_services","type":"radio","label":"Do you offer emergency or after-hours service?","options":["Yes, 24/7","Yes, emergencies only","No"]}]},{"id":"services","title":"Your services","fields":[{"key":"services_offered","type":"multi_select","label":"Services offered","options":["Roof Repairs","Roof Replacements","Chimney Repairs","Siding Repairs","Siding Replacements","Vinyl Siding Installation","Deck Repairs","Deck Replacements","New Deck Construction","Composite Decking (Trex)","Railing Systems","Gutter Cleaning","Gutter Repairs","Gutter Replacements","Gutter Installation","Exterior Painting","Interior Painting","Power Washing","Exterior Renovations","General Home Improvements","Other"]},{"key":"other_services","type":"text","label":"Other services","visible_when":{"operator":"and","conditions":[{"field":"services_offered","op":"contains","value":"Other"}]}},{"key":"primary_service","type":"text","label":"Primary / most profitable service","help_text":"Pick one of the services you selected above."},{"key":"free_offers","type":"multi_select","label":"Do you offer free inspections or estimates?","options":["Free inspection","Free estimate","Both","Neither"]},{"key":"insurance_claims","type":"radio","label":"Do you work with insurance claims?","options":["Yes","No"]},{"key":"accepts_xactimate","type":"radio","label":"Do you accept Xactimate?","options":["Yes","No"],"visible_when":{"operator":"and","conditions":[{"field":"insurance_claims","op":"equals","value":"Yes"}]}},{"key":"differentiators","type":"textarea","label":"What makes you different from competitors?","help_text":"We suggest 3–5 reasons."}]},{"id":"contact_preferences","title":"How customers should reach you","fields":[{"key":"preferred_contact_methods","type":"multi_select","label":"Preferred contact methods","options":["Phone call","SMS / text","WhatsApp","Website form","Email"]},{"key":"form_notification_email","type":"email","label":"Email to receive website form submissions"},{"key":"whatsapp_business","type":"phone","label":"WhatsApp Business number"}]},{"id":"visual_content","title":"Visual content","fields":[{"key":"logo_file","type":"file","label":"Logo","accept":".jpg,.jpeg,.png,.webp,.svg"},{"key":"has_project_photos","type":"radio","label":"Do you have photos of completed projects?","options":["Yes, I''ll upload now","No, use professional stock photos"]},{"key":"before_after_photos","type":"radio","label":"Do you have before & after photos?","options":["Yes","No"]},{"key":"has_team_photos","type":"radio","label":"Do you have team / truck / uniform photos?","options":["Yes","No"]}]},{"id":"language_audience","title":"Site language & audience","fields":[{"key":"site_language","type":"radio","label":"Website language","options":["English","Spanish","Bilingual (both)"]},{"key":"target_customers","type":"multi_select","label":"Typical customer","options":["Homeowners","Property managers","Commercial","Other"]},{"key":"target_customers_other","type":"text","label":"Other customer type","visible_when":{"operator":"and","conditions":[{"field":"target_customers","op":"contains","value":"Other"}]}}]},{"id":"brand_style","title":"Brand & style","fields":[{"key":"brand_colors_option","type":"radio","label":"Do you have specific brand colors?","options":["Yes","No, use colors from the logo"]},{"key":"brand_color_1","type":"text","label":"Primary color","visible_when":{"operator":"and","conditions":[{"field":"brand_colors_option","op":"equals","value":"Yes"}]}},{"key":"brand_color_2","type":"text","label":"Secondary color","visible_when":{"operator":"and","conditions":[{"field":"brand_colors_option","op":"equals","value":"Yes"}]}},{"key":"brand_color_3","type":"text","label":"Accent color","visible_when":{"operator":"and","conditions":[{"field":"brand_colors_option","op":"equals","value":"Yes"}]}},{"key":"reference_sites","type":"dynamic_list","label":"Reference websites","min_items":0,"add_button_label":"Add reference site","item_placeholder":"www.example.com"},{"key":"site_exclusions","type":"textarea","label":"Anything you do NOT want on your site?"}]},{"id":"extras","title":"Extras","fields":[{"key":"wants_blog","type":"radio","label":"Do you want a blog on your site?","options":["Yes","No"]},{"key":"client_notes","type":"textarea","label":"Additional notes"},{"key":"brief_confirmation","type":"checkbox","label":"I confirm the information provided is accurate and authorize its use for my website project.","required":true}]}]}'::jsonb;
begin
  update public.form_templates
  set schema = contractor_schema,
      updated_at = now()
  where is_system = true
    and slug = 'project_brief';

  update public.form_instances fi
  set schema = contractor_schema,
      updated_at = now()
  where fi.slug = 'project_brief';
end $$;
